Below is a **complete, self‑contained binding** for the C++ `libpcapng` iterator.  
It consists of:

1. **`pcapng.mli`** – the public OCaml interface that library users will see.  
2. **`pcapng_stubs.cpp`** – the C‑/C++‑side glue code that talks to `libpcapng` and to the OCaml runtime.

You can drop the two files into a directory, compile the stub with a C++ compiler, and link it with the OCaml code.  
The design mirrors the “row‑wise” APIs you see in Pandas / Polars – the user supplies a **callback** that is invoked for every frame the iterator yields.

---

## 1️⃣  `pcapng.mli` – public OCaml interface

```ocaml
(* ----------------------------------------------------------------------
   pcapng.mli – public interface for the OCaml bindings to libpcapng
   ---------------------------------------------------------------------- *)

(** Abstract handle that owns the underlying C++ iterator. *)
type t

(** A single captured frame.  The fields are deliberately simple so that the
    callback can pattern‑match on them without any extra indirection. *)
type frame = {
  timestamp    : float;      (** Seconds since the Unix epoch, with sub‑second
                                 precision (as a float). *)
  captured_len : int;        (** Number of bytes actually stored in the file. *)
  orig_len    : int;         (** Original length of the packet on the wire. *)
  data        : bytes;       (** Raw packet bytes – a copy of the C++ buffer. *)
}

(** Raised when the underlying C++ library reports an error.  The string
    contains the original error message from libpcapng. *)
exception Error of string

(** Open a pcap‑ng file and create a fresh iterator.  The iterator is owned
    by the returned handle; you must call {!close} when you are done. *)
val open_file : string -> t

(** Explicitly close the handle.  After this call the handle must no longer be
    used.  The finaliser will also close the file automatically if the user
    forgets to call it. *)
val close : t -> unit

(** Iterate over **all** frames in the file, invoking the supplied callback for
    each frame.  The callback runs in the same OCaml thread as the caller; any
    exception raised by the callback aborts the iteration and propagates to the
    caller.  This is the “per‑row” API that mimics Pandas/Polars. *)
val iter : t -> (frame -> unit) -> unit

(** Return the next frame, if any.  This is a low‑level primitive that you can
    combine with your own loops if you need more control. *)
val next : t -> frame option

(** Fold over the frames, very much like `List.fold_left`.  The implementation
    simply re‑uses {!iter} under the hood. *)
val fold : t -> ('a -> frame -> 'a) -> 'a -> 'a
```

*The module implementation (`pcapng.ml`) will contain only a few `external`
declarations that forward to the C++ stubs; the user‑facing API is fully described
by the above signature.*

---

## 2️⃣  `pcapng_stubs.cpp` – C/C++ glue

> **Important:** The stub must be compiled as **C++** (e.g. `g++ -c -std=c++17
> pcapng_stubs.cpp`).  It links against `libpcapng` (the C++ library you are
> binding to).  The build command typically looks like:

```bash
ocamlopt -c pcapng.mli
ocamlopt -c pcapng.ml               # contains the external declarations
g++ -c -std=c++17 -I$(ocamlc -where) -I/usr/include -fPIC pcapng_stubs.cpp
ocamlopt -a -o pcapng.cma pcapng.cmo pcapng_stubs.o -cclib -lpcapng
```

Below is the full stub source.  It is heavily commented so you can adapt it to
the exact API of `libpcapng` you have at hand.

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp – C++ side of the OCaml bindings to libpcapng
   ---------------------------------------------------------------------- */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <cstring>   // memcpy
#include <memory>    // unique_ptr
#include <stdexcept>

/* ----------------------------------------------------------------------
   libpcapng API (replace the placeholders with the real names from the
   library you are wrapping).  The idea is that the library provides a
   *file* object and an iterator over frames.
   ---------------------------------------------------------------------- */
#include <pcapng.hpp>          // <-- your actual header

// For the purpose of this example we assume the following simple API:
//
//   class pcapng::FileReader {
//   public:
//       explicit FileReader(const std::string& filename);
//       ~FileReader();
//       // iterator over frames
//       class iterator {
//       public:
//           iterator();
//           iterator(const iterator&);
//           iterator& operator++();        // advance
//           bool operator==(const iterator&) const;
//           bool operator!=(const iterator&) const;
//           const pcapng::Frame& operator*() const; // deref
//       };
//       iterator begin() const;
//       iterator end()   const;
//   };
//
//   struct Frame {
//       uint64_t   timestamp_us;   // microseconds since epoch
//       uint32_t   captured_len;
//       uint32_t   orig_len;
//       const uint8_t* data;       // pointer valid as long as iterator lives
//   };
//
// The stub below adapts that API to OCaml.  If your library differs, adjust the
// wrapper class accordingly.

namespace pcapng_binding {

/* ----------------------------------------------------------------------
   Wrapper that owns the libpcapng iterator.
   ---------------------------------------------------------------------- */
class Reader {
public:
    explicit Reader(const std::string& filename) :
        file_(filename), it_(file_.begin()), end_(file_.end())
    {}

    ~Reader() = default;   // `file_` and iterator objects clean themselves up

    /** Return the next frame if any, otherwise `false`.  The frame data is
        copied into the out‑parameters because the raw pointer is only valid
        while the iterator lives. */
    bool next_frame(uint64_t& ts_us,
                    uint32_t& caplen,
                    uint32_t& origlen,
                    const uint8_t*& data_ptr)
    {
        if (it_ == end_)
            return false;

        const pcapng::Frame& f = *it_;
        ts_us    = f.timestamp_us;
        caplen   = f.captured_len;
        origlen  = f.orig_len;
        data_ptr = f.data;

        ++it_;   // advance for the next call
        return true;
    }

private:
    pcapng::FileReader file_;           // owns the file handle
    pcapng::FileReader::iterator it_;   // current position
    pcapng::FileReader::iterator end_;  // sentinel
};

} // namespace pcapng_binding

/* ----------------------------------------------------------------------
   OCaml custom block handling for the opaque `Reader*`
   ---------------------------------------------------------------------- */

static void caml_reader_finalize(value v) {
    // The block contains a raw pointer; free it.
    pcapng_binding::Reader* r = *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v));
    delete r;
}

/* No comparison, hash, serialization needed – we supply the minimal set. */
static struct custom_operations caml_reader_ops = {
    "pcapng_binding.reader",
    caml_reader_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* Helper to allocate a custom block containing a `Reader*`. */
static value caml_alloc_reader(pcapng_binding::Reader* r) {
    value v = caml_alloc_custom(&caml_reader_ops, sizeof(pcapng_binding::Reader*), 0, 1);
    *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v)) = r;
    return v;
}

/* ----------------------------------------------------------------------
   Exception handling – we expose a single OCaml exception `Error`.
   ---------------------------------------------------------------------- */
static void raise_error(const std::string& msg) {
    static const value *exn = nullptr;
    if (!exn) exn = caml_named_value("Pcapng.Error");
    caml_raise_with_string(*exn, msg.c_str());
}

/* ----------------------------------------------------------------------
   External entry points – each corresponds to a function declared in
   `pcapng.ml`.  All functions are written with the OCaml C‑API macros
   (`CAMLparam`, `CAMLlocal`, `CAMLreturn`) so that the GC sees every OCaml
   value we allocate.
   ---------------------------------------------------------------------- */

/* open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char* path = String_val(v_path);
    try {
        auto* r = new pcapng_binding::Reader(std::string(path));
        v_res = caml_alloc_reader(r);
    } catch (const std::exception& e) {
        raise_error(e.what());
    }
    CAMLreturn(v_res);
}

/* close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_reader) {
    CAMLparam1(v_reader);
    // The finaliser already frees the object; we just delete the pointer now.
    pcapng_binding::Reader* r = *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v_reader));
    delete r;
    // Overwrite the block with a dummy value so that a double‑close segfaults
    // rather than silently doing nothing.
    *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v_reader)) = nullptr;
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Helper: build an OCaml `frame` record.
   The OCaml type is declared as:
     type frame = { timestamp: float; captured_len: int; orig_len: int; data: bytes }
   which corresponds to a 4‑field record with tag 0 (the only constructor).
   ---------------------------------------------------------------------- */
static value make_ocaml_frame(uint64_t ts_us,
                              uint32_t caplen,
                              uint32_t origlen,
                              const uint8_t* data_ptr)
{
    CAMLparam0();
    CAMLlocal3(v_frame, v_data, v_ts);

    // timestamp: convert microseconds → seconds (float)
    v_ts = caml_copy_double(static_cast<double>(ts_us) / 1e6);

    // data: allocate a fresh OCaml bytes and copy the payload
    v_data = caml_alloc_string(caplen);
    memcpy(String_val(v_data), data_ptr, caplen);

    // allocate the record (4 fields)
    v_frame = caml_alloc(4, 0);               // tag 0 = the only constructor
    Store_field(v_frame, 0, v_ts);
    Store_field(v_frame, 1, Val_int(static_cast<int>(caplen)));
    Store_field(v_frame, 2, Val_int(static_cast<int>(origlen)));
    Store_field(v_frame, 3, v_data);

    CAMLreturn(v_frame);
}

/* iter : t -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter(value v_reader, value v_cb) {
    CAMLparam2(v_reader, v_cb);
    CAMLlocal1(v_frame);
    pcapng_binding::Reader* r = *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v_reader));

    if (!r) caml_failwith("Pcapng.iter: called on a closed reader");

    // Make sure the callback is rooted for the duration of the loop.
    // (CAMLparam already does that, but we keep a local copy for clarity.)
    value cb = v_cb;

    // Iterate over frames.
    while (true) {
        uint64_t ts_us;
        uint32_t caplen, origlen;
        const uint8_t* data_ptr;

        if (!r->next_frame(ts_us, caplen, origlen, data_ptr))
            break;   // reached end of file

        // Build the OCaml frame value.
        v_frame = make_ocaml_frame(ts_us, caplen, origlen, data_ptr);

        // Call the user‑supplied OCaml function.
        // Use `caml_callback_exn` so we can detect exceptions.
        value res = caml_callback_exn(cb, v_frame);
        if (Is_exception_result(res)) {
            // Propagate the exception outwards – iteration stops.
            caml_raise(Extract_exception(res));
        }
        // otherwise ignore the result (unit)
    }

    CAMLreturn(Val_unit);
}

/* next : t -> frame option */
extern "C" CAMLprim value caml_pcapng_next(value v_reader) {
    CAMLparam1(v_reader);
    CAMLlocal1(v_opt);
    pcapng_binding::Reader* r = *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v_reader));

    if (!r) caml_failwith("Pcapng.next: called on a closed reader");

    uint64_t ts_us;
    uint32_t caplen, origlen;
    const uint8_t* data_ptr;

    if (!r->next_frame(ts_us, caplen, origlen, data_ptr)) {
        // No more frames → None
        v_opt = Val_int(0);               // 0 = None
    } else {
        // Some frame → Some(frame)
        value v_frame = make_ocaml_frame(ts_us, caplen, origlen, data_ptr);
        v_opt = caml_alloc(1, 0);         // tag 0 = Some
        Store_field(v_opt, 0, v_frame);
    }

    CAMLreturn(v_opt);
}

/* fold : t -> ('a -> frame -> 'a) -> 'a -> 'a
   Implemented by repeatedly calling `next` and feeding the accumulator to the
   user function.  This is a thin wrapper around iter, but written in C for
   efficiency. */
extern "C" CAMLprim value caml_pcapng_fold(value v_reader, value v_f, value v_acc) {
    CAMLparam3(v_reader, v_f, v_acc);
    CAMLlocal2(v_cur, v_opt);
    pcapng_binding::Reader* r = *reinterpret_cast<pcapng_binding::Reader**>(Data_custom_val(v_reader));

    if (!r) caml_failwith("Pcapng.fold: called on a closed reader");

    value acc = v_acc;
    while (true) {
        uint64_t ts_us;
        uint32_t caplen, origlen;
        const uint8_t* data_ptr;

        if (!r->next_frame(ts_us, caplen, origlen, data_ptr))
            break;   // end of iterator

        v_cur = make_ocaml_frame(ts_us, caplen, origlen, data_ptr);
        // Apply the folding function:  acc = f acc cur
        acc = caml_callback_exn(v_f, acc, v_cur);
        if (Is_exception_result(acc)) caml_raise(Extract_exception(acc));
    }

    CAMLreturn(acc);
}

/* ----------------------------------------------------------------------
   Register the OCaml exception name.  This code is executed at load time.
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_init(value unit) {
    CAMLparam1(unit);
    caml_register_named_value("Pcapng.Error", caml_named_value("Pcapng.Error"));
    CAMLreturn(Val_unit);
}

/* The stub is compiled with `-c -fPIC` and linked with the OCaml runtime.
   The only external symbols that OCaml will see are the functions above,
   each declared with `CAMLprim`. */
```

